#include <iostream>
#include <iomanip>
using namespace std;

int main() {
    cout << "7 / 2 = " << 7 / 2 << endl;
    cout << "7.0 / 2 = " << 7.0 / 2 << endl;
    cout << "7 / 2.0 = " << 7 / 2.0 << endl;

    int sum = 85;
    int cnt = 3;
    cout << fixed << setprecision(2);

    // Wrong: integer division first, then convert to double
    double avg1 = sum / cnt;
    cout << "sum/cnt = " << avg1 << endl;

    // Correct: convert first, then divide
    double avg2 = (double)sum / cnt;
    cout << "(double)sum/cnt = " << avg2 << endl;

    // Also correct
    double avg3 = 1.0 * sum / cnt;
    cout << "1.0*sum/cnt = " << avg3 << endl;

    return 0;
}

