#include <iostream>
#include <algorithm>
#include <vector>
using namespace std;

int main() {
    int a[] = {5, 3, 1, 4, 2};
    int n = 5;

    sort(a, a + n);
    cout << "Correct sort(a, a+n): ";
    for (int i = 0; i < n; i++) cout << a[i] << " ";
    cout << endl;

    int b[] = {9, 7, 3, 8, 2};
    sort(b, b + n);
    cout << "Correct sort(b, b+n): ";
    for (int i = 0; i < n; i++) cout << b[i] << " ";
    cout << endl;

    // Wrong: sort(b, b + n - 1) would miss the last element
    // sort(b, b + n - 1);
    // cout << "Wrong sort(b, b+n-1): ";
    // for (int i = 0; i < n; i++) cout << b[i] << " ";
    // cout << endl;  // output: 2 3 7 8 9  wait, no: 2 7 3 8 9

    vector<int> v = {10, 40, 20, 50, 30};
    sort(v.begin(), v.end());
    cout << "Vector sort: ";
    for (int i = 0; i < v.size(); i++) cout << v[i] << " ";
    cout << endl;

    return 0;
}

#include <iostream>
#include <queue>
#include <vector>
using namespace std;

int main() {
    priority_queue<int> maxPQ;
    maxPQ.push(3);
    maxPQ.push(1);
    maxPQ.push(4);
    maxPQ.push(1);
    maxPQ.push(5);

    cout << "Max heap (default): ";
    while (!maxPQ.empty()) {
        cout << maxPQ.top() << " ";
        maxPQ.pop();
    }
    cout << endl;

    priority_queue<int, vector<int>, greater<int>> minPQ;
    minPQ.push(3);
    minPQ.push(1);
    minPQ.push(4);
    minPQ.push(1);
    minPQ.push(5);

    cout << "Min heap (greater): ";
    while (!minPQ.empty()) {
        cout << minPQ.top() << " ";
        minPQ.pop();
    }
    cout << endl;

    return 0;
}

