#include <iostream>
#include <cmath>
using namespace std;

int main() {
    double a = 0.1 + 0.2;
    double b = 0.3;

    cout << "a = " << a << endl;
    cout << "b = " << b << endl;
    cout << "(a == b) = " << (a == b) << endl;

    double eps = 1e-9;
    cout << "(fabs(a-b) < eps) = " << (fabs(a - b) < eps) << endl;

    double x = 1.0 / 3.0 * 3.0;
    cout << "1/3*3 = " << x << endl;
    cout << "(x == 1.0) = " << (x == 1.0) << endl;
    cout << "(fabs(x-1.0) < eps) = " << (fabs(x - 1.0) < eps) << endl;

    return 0;
}

